  LOW = 'Baixo',
  CHANGE_REQUIRED = 'Sujeito a Troca',
  MINOR_DEFECT = 'Defeito Leve',
  MAJOR_DEFECT = 'Defeito Grave'
}

export interface VehicleInfo {
  brandModel: string;
