import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import Header from './components/Header';
import InspectionForm from './components/InspectionForm';
import ReportModal from './components/ReportModal';
import { InspectionData, InspectionStatus } from './types';

const App: React.FC = () => {
  const [showReport, setShowReport] = useState(false);
  const [formData, setFormData] = useState<InspectionData>({
    vehicle: { brandModel: '', year: '', plate: '', mileage: '', fuelLevel: '50%' },
    tires: {
      grooves: InspectionStatus.GOOD,
      pressure: InspectionStatus.GOOD,
      spare: InspectionStatus.GOOD,
    },
    fluids: {
      engineOil: InspectionStatus.OK,
      brakeFluid: InspectionStatus.OK,
      transmissionFluid: InspectionStatus.OK,
    },
    safety: {
      headlights: InspectionStatus.OK,
      tailLights: InspectionStatus.OK,
      turnSignals: InspectionStatus.OK,
      wipers: InspectionStatus.OK,
    },
    electrical: 4,
    interior: 4,
    equipment: {
      triangle: false,
      extinguisher: false,
      tireWrench: false,
    },
    partsUsed: '',
    observations: ''
  });

  const handleSubmit = (data: InspectionData) => {
    setFormData(data);
    setShowReport(true);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-12">
      <Header />

      <main className="max-w-4xl mx-auto px-4 pt-24">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-slate-800">Check-out de Veículo</h1>
          <p className="text-slate-500">Realize a inspeção final antes da entrega ao cliente.</p>
        </div>

        <InspectionForm initialData={formData} onSubmit={handleSubmit} />
      </main>

      {showReport && (
        <ReportModal 
          data={formData} 
          onClose={() => setShowReport(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { InspectionData, InspectionStatus } from '../types';
import FormCard from './FormCard';
import RatingSelector from './RatingSelector';

interface Props {
  initialData: InspectionData;
  onSubmit: (data: InspectionData) => void;
}

const InspectionForm: React.FC<Props> = ({ initialData, onSubmit }) => {
  const [data, setData] = useState<InspectionData>(initialData);

  const handleInputChange = (section: keyof InspectionData, field: string, value: any) => {
    setData(prev => {
      if (typeof prev[section] === 'object' && prev[section] !== null) {
        return {
          ...prev,
          [section]: {
            ...(prev[section] as object),
            [field]: value
          }
        };
      }
      return { ...prev, [section]: value };
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(data);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {/* Veículo */}
      <FormCard title="Informações do Veículo" icon="fa-car">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Marca / Modelo / Ano *</label>
            <input 
              required
              className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-cyan-500 focus:border-cyan-500 outline-none transition-all"
              placeholder="Ex: Toyota Corolla 2022"
              value={data.vehicle.brandModel}
              onChange={(e) => handleInputChange('vehicle', 'brandModel', e.target.value)}
            />
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Placa</label>
              <input 
                className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-cyan-500 outline-none"
                placeholder="ABC-1234"
                value={data.vehicle.plate}
                onChange={(e) => handleInputChange('vehicle', 'plate', e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Quilometragem</label>
              <input 
                className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-cyan-500 outline-none"
                placeholder="Ex: 45.000"
                value={data.vehicle.mileage}
                onChange={(e) => handleInputChange('vehicle', 'mileage', e.target.value)}
              />
            </div>
          </div>
        </div>
      </FormCard>

      {/* Pneus */}
      <FormCard title="Avaliação dos Pneus" icon="fa-circle-notch">
        <div className="space-y-4">
          {[
            { id: 'grooves', label: 'Estado dos sulcos (profundidade)' },
            { id: 'pressure', label: 'Pressão dos pneus (calibragem)' },
            { id: 'spare', label: 'Estado do pneu sobressalente (estepe)' }
          ].map(item => (
            <div key={item.id} className="flex flex-col md:flex-row md:items-center justify-between gap-2 p-3 bg-slate-50 rounded-lg">
              <span className="text-sm font-medium text-slate-700">{item.label}</span>
              <div className="flex flex-wrap gap-2">
                {[InspectionStatus.EXCELLENT, InspectionStatus.GOOD, InspectionStatus.ACCEPTABLE, InspectionStatus.REPLACE].map(status => (
                  <button
                    key={status}
                    type="button"
                    onClick={() => handleInputChange('tires', item.id, status)}
                    className={`px-3 py-1 text-xs rounded-full border transition-all ${
                      data.tires[item.id as keyof typeof data.tires] === status
                        ? 'bg-cyan-500 text-white border-cyan-500 shadow-sm'
                        : 'bg-white text-slate-500 border-slate-200 hover:border-cyan-300'
                    }`}
                  >
                    {status}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </FormCard>

      {/* Fluidos */}
      <FormCard title="Verificação dos Fluidos" icon="fa-oil-can">
        <div className="space-y-4">
          {[
            { id: 'engineOil', label: 'Nível do Óleo do Motor' },
            { id: 'brakeFluid', label: 'Nível do Fluido de Freio' },
            { id: 'transmissionFluid', label: 'Nível do Fluido da Transmissão' }
          ].map(item => (
            <div key={item.id} className="flex flex-col md:flex-row md:items-center justify-between gap-2 p-3 bg-slate-50 rounded-lg">
              <span className="text-sm font-medium text-slate-700">{item.label}</span>
              <div className="flex flex-wrap gap-2">
                {[InspectionStatus.OK, InspectionStatus.LOW, InspectionStatus.CHANGE_REQUIRED].map(status => (
                  <button
                    key={status}
                    type="button"
                    onClick={() => handleInputChange('fluids', item.id, status)}
                    className={`px-3 py-1 text-xs rounded-full border transition-all ${
                      data.fluids[item.id as keyof typeof data.fluids] === status
