                    }`}
                  >
                    {status}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </FormCard>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Elétrico */}
        <FormCard title="Bateria e Sistema Elétrico" icon="fa-bolt">
          <div className="p-4 bg-slate-50 rounded-lg">
            <RatingSelector 
              label="Condição Geral" 
              value={data.electrical} 
              onChange={(val) => handleInputChange('electrical', '', val)} 
              labels={['Ruim', '2', '3', '4', 'Ótima']}
            />
          </div>
        </FormCard>

        {/* Interior */}
        <FormCard title="Avaliação do Interior" icon="fa-couch">
          <div className="p-4 bg-slate-50 rounded-lg">
            <RatingSelector 
              label="Limpeza / Estofados" 
              value={data.interior} 
              onChange={(val) => handleInputChange('interior', '', val)} 
            />
          </div>
        </FormCard>
      </div>

      {/* Equipamentos */}
      <FormCard title="Equipamentos Obrigatórios" icon="fa-toolbox">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {[
            { id: 'triangle', label: 'Triângulo' },
            { id: 'extinguisher', label: 'Extintor' },
            { id: 'tireWrench', label: 'Chave de Roda' }
          ].map(item => (
            <label key={item.id} className="flex items-center space-x-3 p-4 bg-slate-50 rounded-lg cursor-pointer hover:bg-slate-100 transition-colors">
              <input 
                type="checkbox"
                className="w-5 h-5 text-cyan-500 border-slate-300 rounded focus:ring-cyan-500"
