              />
              <span className="text-sm font-semibold text-slate-700">{item.label}</span>
            </label>
          ))}
        </div>
      </FormCard>

      {/* Peças e Observações */}
      <FormCard title="Detalhamento do Serviço" icon="fa-list-check">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Peças utilizadas no conserto do veículo</label>
            <textarea 
              rows={3}
              className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-cyan-500 outline-none"
              placeholder="Liste as peças substituídas..."
              value={data.partsUsed}
              onChange={(e) => handleInputChange('partsUsed', '', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Observações Adicionais</label>
            <textarea 
              rows={3}
              className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-cyan-500 outline-none"
              placeholder="Algum ponto que o cliente deve saber?"
              value={data.observations}
              onChange={(e) => handleInputChange('observations', '', e.target.value)}
            />
          </div>
        </div>
      </FormCard>

      <button 
        type="submit"
        className="w-full py-4 bg-cyan-500 hover:bg-cyan-600 text-white font-bold rounded-xl shadow-lg shadow-cyan-200 transition-all transform hover:scale-[1.01] active:scale-95 flex items-center justify-center space-x-2"
      >
        <i className="fas fa-check-circle"></i>
        <span>Finalizar Inspeção e Gerar Relatório</span>
      </button>
    </form>
