import React from 'react';

interface Props {
  label: string;
  value: number;
  onChange: (val: number) => void;
  labels?: string[];
}

const RatingSelector: React.FC<Props> = ({ label, value, onChange, labels }) => {
  const options = labels || ['1', '2', '3', '4', '5'];

  return (
    <div className="space-y-3">
      <div className="flex justify-between items-center">
        <span className="text-sm font-semibold text-slate-700">{label}</span>
        <span className="text-sm font-bold text-cyan-600 bg-cyan-50 px-2 py-0.5 rounded">
          {value} / 5
        </span>
      </div>
      <div className="flex justify-between items-center space-x-1">
        {[1, 2, 3, 4, 5].map((num, idx) => (
          <button
            key={num}
            type="button"
            onClick={() => onChange(num)}
            className={`flex-1 h-12 rounded-lg border flex flex-col items-center justify-center transition-all ${
              value === num
                ? 'bg-cyan-500 border-cyan-500 text-white shadow-md'
                : 'bg-white border-slate-200 text-slate-400 hover:border-cyan-300'
            }`}
          >
            <span className="text-sm font-bold">{num}</span>
            {labels && (
               <span className="text-[10px] mt-0.5 opacity-80">{labels[idx]}</span>
            )}
          </button>
        ))}
      </div>
    </div>
  );
};

export default RatingSelector;

import { GoogleGenAI } from "@google/genai";
import { InspectionData } from "../types";

/**
 * Nota: O uso do Gemini requer uma chave de API válida configurada no ambiente.
 * Este serviço pode ser usado para gerar uma "conclusão técnica" ou um 
 * "resumo para o cliente" amigável com base nos dados preenchidos.
 */
export const generateAISummary = async (data: InspectionData) => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return "API Key not found";

  const ai = new GoogleGenAI({ apiKey });
  const prompt = `
    Como um consultor técnico de oficina, gere um resumo amigável para o cliente 
    com base nesta inspeção:
    Veículo: ${data.vehicle.brandModel}
    Pneus: ${data.tires.grooves}
    Observações: ${data.observations}
    Peças: ${data.partsUsed}

    Seja profissional, tecnológico e destaque que o carro está pronto para rodar com segurança.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Erro ao gerar resumo AI", error);
    return "Não foi possível gerar o resumo automático.";
  }
};

