export default InspectionForm;

export enum InspectionStatus {
  EXCELLENT = 'Excelente',
  GOOD = 'Bom',
  ACCEPTABLE = 'Aceitável',
  REPLACE = 'Substituição',
  OK = 'OK',
  LOW = 'Baixo',
  CHANGE_REQUIRED = 'Sujeito a Troca',
  MINOR_DEFECT = 'Defeito Leve',
  MAJOR_DEFECT = 'Defeito Grave'
}

export interface ClientInfo {
  name: string;
  phone: string;
}

export interface VehicleInfo {
  brandModel: string;
  year: string;
  plate: string;
  mileage: string;
}

export interface InspectionData {
  id: string;
  date: string;
  client: ClientInfo;
  vehicle: VehicleInfo;
  tires: {
    grooves: InspectionStatus;
    pressure: InspectionStatus;
    spare: InspectionStatus;
  };
  fluids: {
    engineOil: InspectionStatus;
    brakeFluid: InspectionStatus;
    transmissionFluid: InspectionStatus;
    coolant: InspectionStatus;
    wiperFluid: InspectionStatus;
  };
  electrical: {
    batteryHealth: number;
    alternator: InspectionStatus;
    belts: InspectionStatus;
    dashboardLights: boolean;
  };
  safety: {
    headlights: InspectionStatus;
    tailLights: InspectionStatus;
    turnSignals: InspectionStatus;
    wipers: InspectionStatus;
    horn: boolean;
  };
  equipment: {
    triangle: boolean;
    extinguisher: boolean;
    tireWrench: boolean;
    jack: boolean;
  };
  checkout: {
    testDrive: boolean;
    wheelTorque: boolean;
    cleaning: boolean;
    personalObjects: boolean;
  };
  partsUsed: string;
  observations: string;
}

import React, { useState } from 'react';
import { InspectionData } from '../types';

interface Props {
  history: InspectionData[];
  onDelete: (id: string) => void;
}

const HistoryView: React.FC<Props> = ({ history, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const filtered = history.filter(item => 
    item.client.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vehicle.plate.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vehicle.brandModel.toLowerCase().includes(searchTerm.toLowerCase())
  ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="relative">
        <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-slate-300"></i>
        <input 
          type="text"
          placeholder="Buscar por cliente, placa ou modelo..."
          className="w-full pl-12 pr-6 py-4 bg-white border border-slate-100 rounded-2xl shadow-sm focus:ring-2 focus:ring-[#1D63BD] outline-none font-medium text-slate-900"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {filtered.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-slate-200">
          <i className="fas fa-folder-open text-4xl text-slate-200 mb-4"></i>
          <p className="text-slate-400 font-medium">Nenhum registro encontrado.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filtered.map((item) => (
            <div 
              key={item.id}
              className={`bg-white border transition-all duration-300 overflow-hidden ${
                expandedId === item.id 
                  ? 'rounded-[2rem] border-blue-200 shadow-xl shadow-blue-50' 
                  : 'rounded-2xl border-slate-100 hover:border-blue-100'
              }`}
            >
              {/* Header Reduzido */}
              <div 
                className="p-5 flex items-center justify-between cursor-pointer"
                onClick={() => setExpandedId(expandedId === item.id ? null : item.id)}
              >
                <div className="flex items-center space-x-4">
                  <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center text-[#1D63BD]">
                    <i className="fas fa-car"></i>
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-800">{item.client.name}</h4>
                    <p className="text-xs text-slate-400 font-medium">{item.vehicle.brandModel} • <span className="font-mono">{item.vehicle.plate}</span></p>
                  </div>
                </div>
                <div className="flex items-center space-x-4">
                  <span className="hidden sm:block text-[10px] font-bold text-slate-300 uppercase tracking-widest">
                    {new Date(item.date).toLocaleDateString('pt-BR')}
                  </span>
                  <i className={`fas fa-chevron-down text-slate-300 transition-transform ${expandedId === item.id ? 'rotate-180 text-[#1D63BD]' : ''}`}></i>
                </div>
              </div>

              {/* Corpo Expandido */}
              {expandedId === item.id && (
                <div className="px-5 pb-6 border-t border-slate-50 pt-5 space-y-6 animate-in slide-in-from-top-2 duration-300">
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[9px] font-bold text-slate-400 uppercase">Pneus</p>
                      <p className="text-xs font-bold text-slate-700">{item.tires.grooves}</p>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[9px] font-bold text-slate-400 uppercase">Bateria</p>
                      <p className="text-xs font-bold text-slate-700">{item.electrical.batteryHealth}/5</p>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[9px] font-bold text-slate-400 uppercase">Fluidos</p>
                      <p className="text-xs font-bold text-slate-700">{item.fluids.engineOil}</p>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[9px] font-bold text-slate-400 uppercase">Limpeza</p>
                      <p className="text-xs font-bold text-green-600">{item.checkout.cleaning ? 'OK' : 'NÃO'}</p>
                    </div>
                  </div>

                  <div>
                    <h5 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Peças Utilizadas</h5>
                    <p className="text-sm font-medium text-slate-600 bg-blue-50/30 p-3 rounded-xl border border-blue-50">
