      testDrive: false,
      wheelTorque: false,
      cleaning: false,
      personalObjects: true,
    },
    partsUsed: '',
    observations: ''
  });

  // Carregar histórico do localStorage ao iniciar
  useEffect(() => {
    const saved = localStorage.getItem('autocheck_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  const handleSubmit = (data: InspectionData) => {
    setFormData(data);
    setShowReport(true);
  };

  const handleSaveToHistory = (data: InspectionData) => {
    const newHistory = [data, ...history];
    setHistory(newHistory);
    localStorage.setItem('autocheck_history', JSON.stringify(newHistory));
    // Reset form after saving
    setFormData({ ...formData, client: { name: '', phone: '' }, vehicle: { brandModel: '', year: '', plate: '', mileage: '' }, partsUsed: '', observations: '' });
  };

  const handleDeleteHistory = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este registro?')) {
      const newHistory = history.filter(h => h.id !== id);
      setHistory(newHistory);
      localStorage.setItem('autocheck_history', JSON.stringify(newHistory));
    }
  };

  return (
    <div className="min-h-screen bg-[#FDFDFF] pb-20">
      <Header />

      {/* Navegação entre abas personalizada */}
      <div className="max-w-4xl mx-auto px-4 pt-28">
