              <p className="text-slate-400 font-medium mt-1">Preencha os dados para gerar o certificado.</p>
            </div>
            <InspectionForm initialData={formData} onSubmit={handleSubmit} />
          </>
        ) : (
          <>
            <div className="mb-12 text-center sm:text-left">
              <h1 className="text-4xl font-black text-slate-800 tracking-tight">Histórico de <span className="text-[#1D63BD]">Serviços</span></h1>
              <p className="text-slate-400 font-medium mt-1">Clique nos itens para expandir os detalhes.</p>
