    <div className="min-h-screen bg-[#FDFDFF] pb-20">
      <Header />

      <div className="max-w-4xl mx-auto px-4 pt-28">
        <div className="flex p-1.5 bg-slate-100 rounded-2xl w-fit mb-12 mx-auto sm:mx-0">
          <button 
            onClick={() => setActiveTab('form')}
            className={`px-6 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'form' ? 'bg-white text-[#1D63BD] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Nova Inspeção
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`px-6 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-white text-[#1D63BD] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Histórico ({history.length})
          </button>
        </div>

        {activeTab === 'form' ? (
          <>
            <div className="mb-12 text-center sm:text-left animate-in fade-in duration-700">
              <h1 className="text-4xl font-black text-slate-800 tracking-tight">Inspeção <span className="text-[#1D63BD]">Premium</span></h1>
              <p className="text-slate-400 font-medium mt-1">Checklist completo para saída de oficina.</p>
            </div>
            <InspectionForm initialData={formData} onSubmit={handleSubmit} />
          </>
        ) : (
          <>
            <div className="mb-12 text-center sm:text-left animate-in fade-in duration-700">
              <h1 className="text-4xl font-black text-slate-800 tracking-tight">Histórico de <span className="text-[#1D63BD]">Serviços</span></h1>
              <p className="text-slate-400 font-medium mt-1">Gerencie todos os seus relatórios salvos.</p>
            </div>
            <HistoryView 
              history={history} 
              onDelete={handleDeleteHistory} 
              onViewReport={handleViewReport}
            />
          </>
        )}
      </div>

      {showReport && (
        <ReportModal 
          data={formData} 
          onClose={() => setShowReport(false)} 
          onSaveToHistory={handleSaveToHistory}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus } from '../types';
import FormCard from './FormCard';
import RatingSelector from './RatingSelector';

interface Props {
  initialData: InspectionData;
  onSubmit: (data: InspectionData) => void;
}

const InspectionForm: React.FC<Props> = ({ initialData, onSubmit }) => {
  const [data, setData] = useState<InspectionData>(initialData);

  // Atualiza o estado interno se o initialData mudar (importante ao reabrir relatórios)
  useEffect(() => {
    setData(initialData);
  }, [initialData]);

  const handleInputChange = (section: keyof InspectionData, field: string, value: any) => {
    setData(prev => {
      const sectionData = prev[section];
      if (typeof sectionData === 'object' && sectionData !== null && !Array.isArray(sectionData)) {
        return {
          ...prev,
          [section]: {
            ...sectionData,
            [field]: value
          }
        };
      }
      return { ...prev, [section]: value };
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Preserva o ID e Data se já existirem (edição), senão cria novos
    const finalData: InspectionData = {
      ...data,
      id: data.id || `insp-${Date.now()}`,
      date: data.date || new Date().toISOString()
    };
    onSubmit(finalData);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Dados do Cliente */}
      <FormCard title="Dados do Cliente" icon="fa-user-tie">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Nome Completo *</label>
            <input 
              required
              className="w-full px-5 py-3 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-[#1D63BD] outline-none transition-all placeholder:text-slate-300 font-semibold text-slate-900"
              placeholder="Ex: João da Silva"
              value={data.client.name}
              onChange={(e) => handleInputChange('client', 'name', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">WhatsApp / Telefone *</label>
            <input 
              required
              className="w-full px-5 py-3 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-[#1D63BD] outline-none transition-all placeholder:text-slate-300 font-semibold text-slate-900"
              placeholder="11 99999-9999"
              value={data.client.phone}
              onChange={(e) => handleInputChange('client', 'phone', e.target.value)}
            />
          </div>
        </div>
      </FormCard>

      {/* Dados do Veículo */}
      <FormCard title="Dados do Veículo" icon="fa-car-side">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
